// 원본 클래스
public class MyService {
    public void doSomething() {
        // 실제 로직
    }
}

// 프록시 클래스 (스프링이 자동 생성)
public class MyServiceProxy extends MyService {
    @Override
    public void doSomething() {
        // AOP 부가 로직 (Before)
        super.doSomething();
        // AOP 부가 로직 (After)
    }
}

@Service
public class OrderService {

    public void placeOrder() {
        saveOrder(); // @Transactional이 동작하지 않음
    }

    @Transactional
    private void saveOrder() {
        // 트랜잭션이 적용되지 않는다
    }
}
